public static async Task<bool> FollowNpc(int firstNpcId, int finishNpcId)
{
		var startNpc = GameObjectManager.GetObjectsOfType<BattleCharacter>(true, false)
				.Where(obj => !obj.IsVisible && obj.NpcId == firstNpcId)
				.OrderBy(r => r.Distance())
				.FirstOrDefault();
		var finishNpc = GameObjectManager.GetObjectsOfType<BattleCharacter>(true, false)
				.Where(obj => obj.NpcId == finishNpcId)
				.OrderBy(r => r.Distance())
				.FirstOrDefault();

		while (finishNpc != null && !finishNpc.IsVisible)
		{
				if (startNpc != null && ff14bot.Core.Me.Distance2D(startNpc) > 3f)
				{
						Logging.WriteDiagnostic("Following NPC");
						await CommonTasks.MoveTo(startNpc.Location);
				}
		}

		return true;
}


